patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..f508790f1d9a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2169,11 +2169,11 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {

   case Intrinsic::fshl:
   case Intrinsic::fshr: {
-    Value *Op0 = II->getArgOperand(0), *Op1 = II->getArgOperand(1);
+    Value *Op0 = II->getArgOperand(0), *Op1 = II->getArgOperand(1), *Op2 = II->getArgOperand(2);
     Type *Ty = II->getType();
     unsigned BitWidth = Ty->getScalarSizeInBits();
     Constant *ShAmtC;
-    if (match(II->getArgOperand(2), m_ImmConstant(ShAmtC))) {
+    if (match(Op2, m_ImmConstant(ShAmtC))) {
       // Canonicalize a shift amount constant operand to modulo the bit-width.
       Constant *WidthC = ConstantInt::get(Ty, BitWidth);
       Constant *ModuloC =
@@ -2228,6 +2228,25 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
                                      /*MatchBitReversals*/ true))
         return BitOp;
     }
+    // For non-constant shift amount, if we know shift amount is less than
+    // bitwidth, we can simplify certain patterns.
+    if (IID == Intrinsic::fshl) {
+      KnownBits KnownShift = computeKnownBits(Op2, /*Depth=*/0, II);
+      if (KnownShift.getMaxValue().ult(BitWidth)) {
+        // fshl(X, 0, y) -> shl X, y
+        // fshl(X, undef, y) -> shl X, y
+        if (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))
+          return BinaryOperator::CreateShl(Op0, Op2);
+        // fshl(0, X, y) -> lshr X, (BW - y) if y is known non-zero (to avoid
+        // shift by BW). fshl(undef, X, y) similarly.
+        if (match(Op0, m_ZeroInt()) || match(Op0, m_Undef())) {
+          if (isKnownNonZero(Op2, SQ.getWithInstruction(II))) {
+            Value *Sub = Builder.CreateSub(ConstantInt::get(Ty, BitWidth), Op2);
+            return BinaryOperator::CreateLShr(Op1, Sub);
+          }
+        }
+      }
+    }

     // Left or right might be masked.
     if (SimplifyDemandedInstructionBits(*II))
@@ -2240,6 +2259,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       break;
     APInt Op2Demanded = APInt::getLowBitsSet(BitWidth, Log2_32_Ceil(BitWidth));
     KnownBits Op2Known(BitWidth);
+    errs() << "Called SimplifyDemandedBits\n";
     if (SimplifyDemandedBits(II, 2, Op2Demanded, Op2Known))
       return &CI;
     break;

